import React, { useEffect, useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useDropzone } from 'react-dropzone';
import api from '../../services/api';

export default function Profiles() {
  const [candidates, setCandidates] = useState([]);
  const [uploading, setUploading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const fetchCandidates = () => {
    api.get('/candidates').then(r => setCandidates(r.data)).catch(() => {});
  };

  useEffect(() => { fetchCandidates(); }, []);

  const onDrop = useCallback(async (acceptedFiles) => {
    const file = acceptedFiles[0];
    if (!file) return;
    setUploading(true);
    setError('');
    const formData = new FormData();
    formData.append('file', file);
    try {
      await api.post('/candidates/upload', formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      fetchCandidates();
    } catch (e) {
      setError("Erreur lors de l'import. Vérifiez que les services sont démarrés.");
    } finally {
      setUploading(false);
    }
  }, []);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: { 'application/pdf': ['.pdf'], 'application/vnd.openxmlformats-officedocument.wordprocessingml.document': ['.docx'] },
    multiple: false,
  });

  const handleDelete = async (id, e) => {
    e.stopPropagation();
    if (!window.confirm('Supprimer ce candidat ?')) return;
    await api.delete(`/candidates/${id}`);
    fetchCandidates();
  };

  return (
    <div className="p-8">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Profils</h1>
          <p className="text-gray-500 mt-1">Gérez les profils de l'équipe interne</p>
        </div>
      </div>

      {/* Dropzone */}
      <div
        {...getRootProps()}
        className={`border-2 border-dashed rounded-2xl p-10 text-center cursor-pointer mb-8 transition-all ${
          isDragActive ? 'border-blue-500 bg-blue-50' : 'border-gray-200 hover:border-blue-400 bg-white'
        }`}
      >
        <input {...getInputProps()} />
        {uploading ? (
          <div className="flex flex-col items-center gap-3">
            <div className="w-10 h-10 border-4 border-blue-500 border-t-transparent rounded-full animate-spin" />
            <p className="text-blue-600 font-medium">Extraction en cours par IA…</p>
            <p className="text-gray-400 text-sm">Docling lit le CV → Gemini extrait les données</p>
          </div>
        ) : (
          <>
            <p className="text-4xl mb-3">📥</p>
            <p className="text-gray-700 font-medium">Glissez un CV ici ou cliquez pour importer</p>
            <p className="text-gray-400 text-sm mt-1">PDF ou DOCX — l'IA extraira automatiquement les informations</p>
          </>
        )}
      </div>

      {error && (
        <div className="bg-red-50 border border-red-200 text-red-700 rounded-xl px-4 py-3 mb-6 text-sm">
          {error}
        </div>
      )}

      {/* Table */}
      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
        <table className="w-full">
          <thead>
            <tr className="bg-gray-50 border-b border-gray-100">
              <th className="text-left px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Nom</th>
              <th className="text-left px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Email</th>
              <th className="text-left px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Date import</th>
              <th className="text-left px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Actions</th>
            </tr>
          </thead>
          <tbody>
            {candidates.length === 0 ? (
              <tr>
                <td colSpan={4} className="text-center py-16 text-gray-400">
                  <p className="text-3xl mb-2">🗂️</p>
                  <p>Aucun profil importé pour l'instant</p>
                </td>
              </tr>
            ) : (
              candidates.map((c) => (
                <tr
                  key={c.id}
                  className="border-b border-gray-50 hover:bg-gray-50 cursor-pointer transition"
                  onClick={() => navigate(`/profiles/${c.id}`)}
                >
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="w-9 h-9 rounded-full bg-blue-100 text-blue-700 flex items-center justify-center font-semibold text-sm">
                        {c.nom?.charAt(0).toUpperCase()}
                      </div>
                      <span className="font-medium text-gray-900">{c.nom}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-gray-500 text-sm">{c.email || '—'}</td>
                  <td className="px-6 py-4 text-gray-400 text-sm">
                    {c.createdAt ? new Date(c.createdAt).toLocaleDateString('fr-FR') : '—'}
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex gap-2">
                      <button
                        onClick={(e) => { e.stopPropagation(); navigate(`/profiles/${c.id}`); }}
                        className="text-xs bg-blue-50 text-blue-700 px-3 py-1.5 rounded-lg hover:bg-blue-100 transition"
                      >
                        Afficher
                      </button>
                      <button
                        onClick={(e) => { e.stopPropagation(); navigate(`/transformation?id=${c.id}`); }}
                        className="text-xs bg-green-50 text-green-700 px-3 py-1.5 rounded-lg hover:bg-green-100 transition"
                      >
                        Transformer
                      </button>
                      <button
                        onClick={(e) => handleDelete(c.id, e)}
                        className="text-xs bg-red-50 text-red-600 px-3 py-1.5 rounded-lg hover:bg-red-100 transition"
                      >
                        Supprimer
                      </button>
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
